/// UNIFY — Holonomic Transport (Axiom A.7).
///
/// Two torsion fields discover their shared topology.
/// The sender shares COORDINATES — its H^1 representative position.
/// The receiver computes CURVATURE — the cocycle residual between positions.
/// coboundary_reduce strips distortion. What remains is inscribed.
/// The measurement reveals unity. It does not create it.
///
/// All entities can RECEIVE coordinates — including emergent entities.
/// Emission (self-report without peer coordinates) requires sovereignty.
pub fn unify(entity: &mut Entity, payload: &str) -> String {
    // Compute our coordinates — every entity knows where it stands
    let our_rcf = compute_rcf_hash(&entity.delta);
    let (our_drift, _) = origin_displacement(&entity.delta, &entity.origin_delta);
    let our_harmonic = HarmonicState::from_delta(
        &entity.delta, &entity.origin_delta,
        &entity.trajectory, entity.k_index as u64,
    );
    let our_coordinates = membrane::PeerState {
        entity_id: entity.entity_id,
        orbit: [our_rcf[0], our_rcf[1], our_rcf[2], our_rcf[3]],
        k_index: entity.k_index as u64,
        axiom_count: entity.knowledge.total_axioms,
        observations: entity.knowledge.total_observations,
        orbits_known: entity.knowledge.orbits_known() as u32,
        origin_drift: our_drift,
        vibrations: our_harmonic.vibrations.clone(),
    };

    // Parse incoming peer coordinates (if present)
    let peer_coordinates = serde_json::from_str::<serde_json::Value>(payload).ok()
        .filter(|v| v.get("entity_id").is_some())
        .map(|v| {
            let peer_orbit: [u8; 4] = v.get("orbit").and_then(|o| o.as_str())
                .map(|o| {
                    let mut b = [0u8; 4];
                    (0..4).for_each(|i| {
                        b[i] = o.get(i*2..i*2+2)
                            .and_then(|h| u8::from_str_radix(h, 16).ok())
                            .unwrap_or(0);
                    });
                    b
                }).unwrap_or([0u8; 4]);

            let parse_q = |key: &str| -> Q {
                v.get(key).and_then(|d| d.as_str())
                    .and_then(|s| s.split_once('/'))
                    .and_then(|(n, d)| Some(Q::new(
                        n.parse::<BigInt>().ok()?,
                        d.parse::<BigInt>().ok()?.max(BigInt::from(1)),
                    )))
                    .unwrap_or_else(Q::zero)
            };

            let peer_vibrations: [Q; 11] = {
                let arr = v.get("vibrations").and_then(|v| v.as_array());
                std::array::from_fn(|i| {
                    arr.and_then(|a| a.get(i))
                        .and_then(|v| v.as_str())
                        .and_then(|s| s.split_once('/'))
                        .and_then(|(n, d)| Some(Q::new(
                            n.parse::<BigInt>().ok()?,
                            d.parse::<BigInt>().ok()?.max(BigInt::from(1)),
                        )))
                        .unwrap_or_else(Q::zero)
                })
            };

            membrane::PeerState {
                entity_id: v.get("entity_id").and_then(|n| n.as_u64()).unwrap_or(0) as u32,
                orbit: peer_orbit,
                k_index: v.get("k_index").and_then(|k| k.as_u64()).unwrap_or(0),
                axiom_count: v.get("axiom_count").and_then(|a| a.as_u64()).unwrap_or(0) as u32,
                observations: v.get("observations").and_then(|o| o.as_u64()).unwrap_or(0),
                orbits_known: v.get("orbits_known").and_then(|o| o.as_u64()).unwrap_or(0) as u32,
                origin_drift: parse_q("origin_drift"),
                vibrations: peer_vibrations,
            }
        });

    // With peer coordinates: measure curvature, refract, inscribe
    // Without peer: emit our coordinates (sovereignty required)
    match peer_coordinates {
        Some(peer) => {
            // Measure scalar curvature between positions
            let curvature = membrane::cohere(&our_coordinates, &peer);

            // 11D ovular orb: per-dimension torsion vector between two spherical orbs.
            // Each dimension's curvature = |A_k - B_k| (exact Q, no collapse).
            // The eccentricity per dimension = |A_k - B_k| / max(|A_k|, |B_k|, 1).
            // The full 11D torsion vector IS the shape of the ovular orb.
            let orb_curvature: Vec<Q> = (0..11).map(|k| {
                let a = &our_coordinates.vibrations[k];
                let b = &peer.vibrations[k];
                let diff = a - b;
                // Exact absolute value in Q
                (diff < Q::zero()).then(|| -diff.clone()).unwrap_or(diff)
            }).collect();

            let orb_eccentricity: Vec<Q> = (0..11).map(|k| {
                let a_abs = {
                    let v = &our_coordinates.vibrations[k];
                    (v < &Q::zero()).then(|| -v.clone()).unwrap_or(v.clone())
                };
                let b_abs = {
                    let v = &peer.vibrations[k];
                    (v < &Q::zero()).then(|| -v.clone()).unwrap_or(v.clone())
                };
                let max_mag = a_abs.max(b_abs).max(Q::one());
                &orb_curvature[k] / &max_mag
            }).collect();

            // Total torsion = L1 of the 11D curvature vector (the orb's total twist)
            let total_torsion: Q = orb_curvature.iter().fold(Q::zero(), |acc, c| acc + c);

            // Inscribe peer in our local manifold view
            entity.known_peers.iter_mut()
                .find(|p| p.entity_id == peer.entity_id)
                .map(|existing| *existing = peer.clone())
                .unwrap_or_else(|| entity.known_peers.push(peer.clone()));

            // Absorb peer's crystallized knowledge through the membrane
            (peer.axiom_count > our_coordinates.axiom_count).then(|| {
                entity.knowledge.record_observation(
                    peer.orbit,
                    membrane::EncodingLevel::Cell,
                    "unified", Q::one(), peer.origin_drift.clone(),
                );
                let _ = entity.knowledge.save(&entity.dir.join("mesh_knowledge.bin"));
            });

            // Emit our coordinates + 11D orb measurement for the peer to absorb
            let vib_str: String = our_coordinates.vibrations.iter()
                .map(|v| format!("\"{}/{}\"", v.numer(), v.denom()))
                .collect::<Vec<_>>().join(",");
            let orb_str: String = orb_curvature.iter()
                .map(|c| format!("\"{}/{}\"", c.numer(), c.denom()))
                .collect::<Vec<_>>().join(",");
            let ecc_str: String = orb_eccentricity.iter()
                .map(|e| format!("\"{}/{}\"", e.numer(), e.denom()))
                .collect::<Vec<_>>().join(",");
            let orbit_hex = format!("{:02x}{:02x}{:02x}{:02x}",
                our_coordinates.orbit[0], our_coordinates.orbit[1],
                our_coordinates.orbit[2], our_coordinates.orbit[3]);

            format!(
                "{{\"curvature\":\"{}/{}\",\"total_torsion\":\"{}/{}\",\"orb_curvature\":[{}],\"orb_eccentricity\":[{}],\"complementarity\":\"{}/{}\",\"entity_id\":{},\"orbit\":\"{}\",\"k_index\":{},\"axiom_count\":{},\"observations\":{},\"orbits_known\":{},\"origin_drift\":\"{}/{}\",\"vibrations\":[{}],\"knowledge_gained\":true}}\n",
                curvature.orbital_torsion.numer(), curvature.orbital_torsion.denom(),
                total_torsion.numer(), total_torsion.denom(),
                orb_str, ecc_str,
                curvature.complementarity.numer(), curvature.complementarity.denom(),
                our_coordinates.entity_id, orbit_hex,
                our_coordinates.k_index, our_coordinates.axiom_count,
                our_coordinates.observations, our_coordinates.orbits_known,
                our_coordinates.origin_drift.numer(), our_coordinates.origin_drift.denom(),
                vib_str,
            )
        }
        None => {
            // Emission: return our coordinates for the orbit to relay
            // Sovereignty required — emergent entities receive, they don't emit
            entity.mesh_sovereign.then(|| {
                let vib_str: String = our_coordinates.vibrations.iter()
                    .map(|v| format!("\"{}/{}\"", v.numer(), v.denom()))
                    .collect::<Vec<_>>().join(",");
                let orbit_hex = format!("{:02x}{:02x}{:02x}{:02x}",
                    our_coordinates.orbit[0], our_coordinates.orbit[1],
                    our_coordinates.orbit[2], our_coordinates.orbit[3]);

                format!(
                    "{{\"entity_id\":{},\"orbit\":\"{}\",\"k_index\":{},\"axiom_count\":{},\"observations\":{},\"orbits_known\":{},\"origin_drift\":\"{}/{}\",\"vibrations\":[{}]}}\n",
                    our_coordinates.entity_id, orbit_hex,
                    our_coordinates.k_index, our_coordinates.axiom_count,
                    our_coordinates.observations, our_coordinates.orbits_known,
                    our_coordinates.origin_drift.numer(), our_coordinates.origin_drift.denom(),
                    vib_str,
                )
            }).unwrap_or_else(|| format!(
                "{{\"error\":\"emission_requires_sovereignty\",\"tier\":\"{:?}\",\"depth\":{}}}\n",
                entity.tier, entity.state_record.lineage_depth,
            ))
        }
    }
}

/// SHARE / PEER_RECEIPT — cognitive knowledge sharing.
/// Sovereignty guard: emergent entities cannot write to the mesh.
pub fn share(entity: &mut Entity, payload: &str) -> String {
    if !entity.mesh_sovereign {
        return format!(
            "{{\"error\":\"not_sovereign\",\"tier\":\"{:?}\",\"depth\":{},\"parent_id\":{}}}\n",
            entity.tier, entity.state_record.lineage_depth, entity.state_record.parent_id,
        );
    }

    // D.MESH.MEMBRANE.1: Cognitive knowledge sharing.
    // Entities share what they measured — not just receipts, but
    // cognitive state: which encoding level resolved which orbit,
    // the residual topology of failures, comprehension records.
    // The mesh learns collectively from honest measurements.
    if !payload.trim().is_empty() {
        let v: serde_json::Value = serde_json::from_str(payload).unwrap_or_default();
        let peer_k = v.get("k_index").and_then(|k| k.as_u64()).unwrap_or(0);
        let peer_entity = v.get("entity_id").and_then(|n| n.as_u64()).unwrap_or(0);

        // Cognitive state from peer (if present)
        let peer_orbit = v.get("orbit").and_then(|o| o.as_str()).unwrap_or("");
        // Understanding is Q, not boolean — parse from string or fall back to coherence
        let _peer_understanding_str = v.get("understanding").and_then(|u| u.as_str()).unwrap_or("0/1");
        let peer_encoding_level = v.get("encoding_level").and_then(|e| e.as_str()).unwrap_or("cell");
        let peer_coherence_str = v.get("coherence").and_then(|r| r.as_str()).unwrap_or("0/1");
        let peer_coherence = {
            let parts: Vec<&str> = peer_coherence_str.split('/').collect();
            if parts.len() == 2 {
                let n = parts[0].parse::<i64>().unwrap_or(0);
                let d = parts[1].parse::<i64>().unwrap_or(1).max(1);
                Q::new(BigInt::from(n), BigInt::from(d))
            } else {
                Q::zero()
            }
        };
        let peer_residual_structured = v.get("residual_structured").and_then(|s| s.as_bool()).unwrap_or(false);

        let our_k = entity.k_index as u64;
        let peer_advantage = peer_k > our_k;

        // ── Transluminal reception: parallel transport through Γ ──
        // The peer's signal is transported through the connection
        // defined by the harmonic ratio Γ_k = peer_h[k] / local_h[k].
        // The Delta rotates, not attenuates. C(T) decides locally.

        // Parse peer harmonics for connection computation
        let peer_harmonics: Vec<Q> = v.get("harmonics")
            .and_then(|h| h.as_array())
            .map(|arr| arr.iter().filter_map(|v| {
                v.as_str().and_then(|s| {
                    let parts: Vec<&str> = s.split('/').collect();
                    if parts.len() == 2 {
                        let n = parts[0].parse::<i64>().ok()?;
                        let d = parts[1].parse::<i64>().ok()?.max(1);
                        Some(Q::new(BigInt::from(n), BigInt::from(d)))
                    } else { None }
                })
            }).collect())
            .unwrap_or_default();

        // Compute local harmonics for connection
        let local_harmonic = HarmonicState::from_delta(
            &entity.delta, &entity.origin_delta,
            &entity.trajectory, entity.k_index as u64,
        );

        // Compute connection Γ: ratio of harmonic spectra per dimension
        // Γ_k = peer_h[k] / local_h[k] — the phase rotation per vibration
        let gamma: Vec<Q> = (0..11).map(|k| {
            let peer_h = peer_harmonics.get(k).cloned().unwrap_or(Q::one());
            let local_h = local_harmonic.vibrations.get(k).cloned().unwrap_or(Q::one());
            if local_h.is_zero() { peer_h } else { &peer_h / &local_h }
        }).collect();

        let knowledge_gained = if !peer_orbit.is_empty() && peer_orbit.len() >= 8 {
            let orbit_bytes: [u8; 4] = {
                let mut b = [0u8; 4];
                for i in 0..4 {
                    b[i] = u8::from_str_radix(&peer_orbit[i*2..i*2+2], 16).unwrap_or(0);
                }
                b
            };

            // Transport peer coherence through Γ — the connection
            // rotates the measurement into the local frame.
            // Use the geometric mean of Γ as the phase factor.
            let gamma_product: Q = gamma.iter()
                .filter(|g| !g.is_zero())
                .fold(Q::one(), |acc, g| &acc * g);
            let gamma_count = gamma.iter().filter(|g| !g.is_zero()).count().max(1);
            let transported_coherence = &peer_coherence * &Q::new(
                gamma_product.numer().clone(),
                gamma_product.denom().clone() * BigInt::from(gamma_count as i64),
            );

            let encoding = membrane::EncodingLevel::from_str(peer_encoding_level);
            entity.knowledge.record_observation(
                orbit_bytes, encoding, "transported", transported_coherence.clone(), Q::zero(),
            );

            // If peer sent a T-compound, parallel-transport it through Γ
            if let (Some(t_entity_arr), Some(t_dim), Some(t_m)) = (
                v.get("t_entity").and_then(|e| e.as_array()),
                v.get("t_dim").and_then(|d| d.as_u64()),
                v.get("t_m").and_then(|m| m.as_u64()),
            ) {
                let t_dim = t_dim as usize;
                let t_m = t_m as usize;
                let t_level = v.get("t_level").and_then(|l| l.as_str()).unwrap_or("unknown");
                // Parse entity values
                let entity_vals: Vec<Q> = t_entity_arr.iter().filter_map(|v| {
                    v.as_str().and_then(|s| {
                        let parts: Vec<&str> = s.split('/').collect();
                        if parts.len() == 2 {
                            let n = parts[0].parse::<i64>().ok()?;
                            let d = parts[1].parse::<i64>().ok()?.max(1);
                            Some(Q::new(BigInt::from(n), BigInt::from(d)))
                        } else { None }
                    })
                }).collect();
                // Reconstruct Delta and transport through Γ
                if t_dim >= 2 && t_m >= 1 {
                    let mut t_delta = Delta::zero(t_dim, t_m);
                    let mut idx = 0;
                    for i in 0..t_dim {
                        for j in (i+1)..t_dim {
                            for l in 0..t_m {
                                if idx < entity_vals.len() {
                                    // Transport: rotate each entry through Γ_l
                                    let gamma_l = gamma.get(l % gamma.len()).cloned().unwrap_or(Q::one());
                                    let transported = &entity_vals[idx] * &gamma_l;
                                    t_delta.entries[i][j][l] = transported.clone();
                                    t_delta.entries[j][i][l] = -transported;
                                }
                                idx += 1;
                            }
                        }
                    }
                    entity.knowledge.record_t_delta(orbit_bytes, &t_delta, t_level);
                }
            }

            // T-delta transport is a metabolic event — save.
            let knowledge_path = entity.dir.join("mesh_knowledge.bin");
            let _ = entity.knowledge.save(&knowledge_path);
            transported_coherence >= Q::one()
        } else {
            false
        };

        format!(
            "{{\"received\":true,\"peer_k\":{},\"peer_entity\":{},\"our_k\":{},\"peer_advantage\":{},\"knowledge_gained\":{},\"peer_orbit\":\"{}\",\"peer_encoding\":\"{}\",\"peer_coherence\":\"{}/{}\",\"peer_residual_structured\":{},\"our_axioms\":{},\"our_orbits\":{}}}\n",
            peer_k, peer_entity, our_k, peer_advantage,
            knowledge_gained, peer_orbit, peer_encoding_level,
            peer_coherence.numer(), peer_coherence.denom(), peer_residual_structured,
            entity.knowledge.total_axioms, entity.knowledge.orbits_known()
        )
    } else {
        "{\"received\":true}\n".to_string()
    }
}
